class Solution {
    public int nextBeautifulNumber(int n) {
        n++;
        while (!isBeautiful(n)) {
            n++;
        }
        return n;
    }

    private boolean isBeautiful(int num) {
        String str = String.valueOf(num);
        for (char c : str.toCharArray()) {
            int count = 0;
            for (char d : str.toCharArray()) {
                if (c == d) {
                    count++;
                }
            }
            if (count != Character.getNumericValue(c)) {
                return false;
            }
        }
        return true;
    }
}
